8869   // Create new empty VPlan
8870   auto Plan = VPlan::createInitialVPlan(
8871       createTripCountSCEV(Legal->getWidestInductionType(), PSE, OrigLoop),
8872       *PSE.getSE());
8873 
8874   // Build hierarchical CFG
8875   VPlanHCFGBuilder HCFGBuilder(OrigLoop, LI, *Plan);
8876   HCFGBuilder.buildHierarchicalCFG();
